#!/usr/bin/env node

import { ethers } from 'ethers';

const BASE_URL = process.env.HYPERLIQUID_TESTNET === '1'
  ? 'https://api.hyperliquid-testnet.xyz'
  : 'https://api.hyperliquid.xyz';

const PRIVATE_KEY = process.env.HYPERLIQUID_PRIVATE_KEY;
const ADDRESS = process.env.HYPERLIQUID_ADDRESS || (PRIVATE_KEY ? new ethers.Wallet(PRIVATE_KEY).address : null);

async function info(payload) {
  const res = await fetch(`${BASE_URL}/info`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  });
  return res.json();
}

async function signAndSend(action) {
  if (!PRIVATE_KEY) throw new Error('Private key required. Set HYPERLIQUID_PRIVATE_KEY environment variable.');
  const wallet = new ethers.Wallet(PRIVATE_KEY);
  const timestamp = Date.now();

  const msgToSign = ethers.solidityPackedKeccak256(
    ['string', 'uint64', 'bool'],
    [JSON.stringify(action), timestamp, false]
  );

  const sig = await wallet.signMessage(ethers.getBytes(msgToSign));
  const { r, s, v } = ethers.Signature.from(sig);

  const res = await fetch(`${BASE_URL}/exchange`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ action, signature: { r, s, v }, nonce: timestamp }),
  });
  return res.json();
}

async function getMeta() {
  return info({ type: 'meta' });
}

async function getAssetIndex(coin) {
  const meta = await getMeta();
  const idx = meta.universe.findIndex(a => a.name === coin);
  if (idx === -1) throw new Error(`Unknown coin: ${coin}`);
  return idx;
}

async function getPrice(coin) {
  const mids = await info({ type: 'allMids' });
  const price = mids[coin];
  if (!price) throw new Error(`No price for ${coin}`);
  return parseFloat(price);
}

async function balance() {
  if (!ADDRESS) throw new Error('Address required. Set HYPERLIQUID_ADDRESS or HYPERLIQUID_PRIVATE_KEY environment variable.');
  const state = await info({ type: 'clearinghouseState', user: ADDRESS });
  console.log(JSON.stringify(state, null, 2));
}

async function positions(address) {
  const addr = address || ADDRESS;
  if (!addr) throw new Error('Address required. Set HYPERLIQUID_ADDRESS or HYPERLIQUID_PRIVATE_KEY environment variable.');
  const state = await info({ type: 'clearinghouseState', user: addr });
  console.log(JSON.stringify(state.assetPositions, null, 2));
}

async function orders() {
  if (!ADDRESS) throw new Error('Address required. Set HYPERLIQUID_ADDRESS or HYPERLIQUID_PRIVATE_KEY environment variable

