  if (!PRIVATE_KEY) throw new Error('Private key required for trading operations. Set HYPERLIQUID_PRIVATE_KEY.');
  const wallet = new ethers.Wallet(PRIVATE_KEY);
  const timestamp = Date.now();

  const msgToSign = ethers.solidityPackedKeccak256(
    ['string', 'uint64', 'bool'],
    [JSON.stringify(action), timestamp, false]
  );
  const sig = await wallet.signMessage(ethers.getBytes(msgToSign));
  const { r, s, v } = ethers.Signature.from(sig);

  const payload = {
    action,
    nonce: timestamp,
    signature: { r, s, v },
  };

  const res = await fetch(`${BASE_URL}/exchange`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  });
  return res.json();
}

async function getAssetIndex(coin) {
  const meta = await info('meta');
  const idx = meta.universe.findIndex(a => a.name === coin);
  if (idx === -1) throw new Error(`Unknown coin: ${coin}. Use 'meta' command to list available coins.`);
  return idx;
}

async function placeOrder(coin, isBuy, price, size, reduceOnly = false) {
  const a = await getAssetIndex(coin);
